#!/usr/bin/env python3
import base64, os

files = {"app/learn/page.tsx": "", "app/learn/[moduleSlug]/page.tsx": "", "app/learn/[moduleSlug]/[lessonSlug]/page.tsx": "", "components/Sidebar.tsx": "", "components/Dashboard.tsx": ""}

for rel_path, b64content in files.items():
    full_path = os.path.join(os.getcwd(), rel_path)
    os.makedirs(os.path.dirname(full_path), exist_ok=True)
    content = base64.b64decode(b64content).decode()
    with open(full_path, 'w') as f:
        f.write(content)
    print(f'  ✅ {rel_path}')

print()
print('🎉 ¡Todos los archivos creados!')
